    //Acuario
    "horoscope.data.advice.aquarius.0": "Sé curioso y abierto a nuevas ideas hoy.",
    "horoscope.data.advice.aquarius.1": "Busca comprender antes de juzgar una situación.",
    "horoscope.data.advice.aquarius.2": "Expresa tus ideas, aunque parezcan diferentes; serán útiles.",
